  uint uVar2;
  uint uVar3;
  uint uVar4;

  uVar4 = 0;
  uVar1 = (ushort)MXCSR & 0x8040;
  if (uVar1 == 0x8000) {
    uVar4 = 0xc00;
  }
  else if (uVar1 == 0x40) {
    uVar4 = 0x800;
  }
  else if (uVar1 == 0x8040) {
    uVar4 = 0x400;
  }
  uVar2 = MXCSR & 0x6000;
  if (uVar2 == 0) {
