  }
  uVar2 = (MXCSR >> 8 & 1) << 5 | (MXCSR >> 7 & 1) << 4 | (MXCSR >> 9 & 1) << 3 |
          (MXCSR >> 10 & 1) << 2 | (MXCSR >> 0xb & 1) * 2 | MXCSR >> 0xc & 1;
  return uVar3 << 0x16 | uVar2 << 0x18 | uVar2 | uVar3 | uVar4;
}
